INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'eea8b401-8a07-4aa5-9f6e-f06281cf7d7d',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS Middleware — Pipeline Order, Global Registration, and Route Scoping$escape$,
  $escape$NestJS middleware runs before route handlers and interceptors, sitting closest to the raw Express/Fastify layer. You register middleware via the `configure()` method in a module implementing `NestModule` — not through decorators. Route-specific middleware uses `.forRoutes()` with a path string, a `RouteInfo` object specifying HTTP method, or a controller class directly. Global middleware skips `configure()` entirely: use `app.use()` in `main.ts`, which applies it before NestJS's own request lifecycle. Ordering is determined by registration sequence — middleware registered first runs first. This matters when chaining auth, logging, or body-parsing middleware that downstream handlers depend on. A common mistake is registering a JWT-extraction middleware after a logging middleware that tries to read `req.user` — it'll always be undefined. For class-based middleware, implement the `NestMiddleware` interface with an `use(req, res, next)` method and inject services via the constructor. Functional middleware is simpler but loses DI. Middleware cannot access NestJS's `ExecutionContext`, so for guard-level logic (roles, policies), move that into Guards instead.$escape$,
  $escape$// logger.middleware.ts
@Injectable()
export class LoggerMiddleware implements NestMiddleware {
  constructor(private readonly logService: LogService) {}

  use(req: Request, res: Response, next: NextFunction) {
    this.logService.log(`${req.method} ${req.url}`);
    next();
  }
}

// app.module.ts
export class AppModule implements NestModule {
  configure(consumer: MiddlewareConsumer) {
    consumer
      .apply(LoggerMiddleware)
      .forRoutes({ path: 'users*', method: RequestMethod.ALL });
  }
}$escape$,
  $escape$typescript$escape$,
