INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bb44862e-7ef7-497f-a2c9-a344fcd2336e',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS Routing — Controllers, Route Params, and Prefix Grouping$escape$,
  $escape$NestJS routes are declared via decorators on controller classes. The `@Controller('prefix')` decorator sets a route prefix for every handler inside it, so `@Controller('users')` + `@Get(':id')` resolves to `GET /users/:id`. Route parameters are extracted with `@Param('id')` — or `@Param()` for the full params object. For nested resources, compose prefixes manually: `@Controller('posts/:postId/comments')` with `@Get(':id')` gives you `GET /posts/:postId/comments/:id`. Wildcard segments use `*`: `@Get('ab*cd')` matches `abXYZcd`. Query strings are separate — use `@Query('page')` for `?page=2`. Controllers are grouped into modules, making feature-level prefix isolation clean: a `UsersModule` owns `UsersController`, and its prefix never bleeds into other domains. For versioning, NestJS supports URI versioning natively via `enableVersioning({ type: VersioningType.URI })` in `main.ts`, then `@Version('1')` on a controller or handler, resolving to `/v1/users`. Avoid scattering route logic outside controllers — Nest's DI and module system depend on this structure.$escape$,
  $escape$@Controller('posts/:postId/comments')
export class CommentsController {
  @Get()
  findAll(@Param('postId') postId: string, @Query('page') page = '1') {
    return { postId, page };
  }

  @Get(':id')
  findOne(@Param('postId') postId: string, @Param('id') id: string) {
    return { postId, commentId: id };
  }

  @Post()
  @HttpCode(201)
  create(@Param('postId') postId: string, @Body() dto: CreateCommentDto) {
    return { postId, dto };
  }
}$escape$,
