INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3f28df08-3d2a-4d0a-b45e-a7c44e769702',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS Structured Logging — Correlation IDs and Request Middleware Done Right$escape$,
  $escape$NestJS's built-in Logger is fine for development, but production systems need structured logs with correlation IDs to trace requests across services. Replace the default logger with a custom LoggerService backed by Pino or Winston, then inject it globally via app.useLogger().

For correlation IDs, create a middleware that reads X-Correlation-ID from incoming headers (or generates a UUID v4 fallback), stores it in AsyncLocalStorage via a dedicated CorrelationService, and sets it on the response header. Bind this middleware to every route using app.use() in main.ts.

In your LoggerService, pull the correlation ID from CorrelationService on every log call and merge it into the structured payload. This ensures every log line — whether emitted from a guard, interceptor, or deep service — carries the same request-scoped ID without prop-drilling.

Use an HTTP interceptor (not middleware) for request/response logging: interceptors have access to the ExecutionContext and can measure precise response time via RxJS tap(). Log method, URL, statusCode, and durationMs as structured fields, not interpolated strings.$escape$,
  $escape$// correlation.middleware.ts
@Injectable()
export class CorrelationMiddleware implements NestMiddleware {
  constructor(private readonly correlation: CorrelationService) {}

  use(req: Request, res: Response, next: NextFunction) {
    const id = (req.headers['x-correlation-id'] as string) ?? randomUUID();
    res.setHeader('x-correlation-id', id);
    this.correlation.run(id, next);
  }
}

// correlation.service.ts
@Injectable()
export class CorrelationService {
  private readonly storage = new AsyncLocalStorage<string>();
  run(id: string, fn: () => void) { this.storage.run(id, fn); }
  getId(): string | undefined { return this.storage.getStore(); }
}$escape$,
