INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c6bb42dd-4b98-4239-9e07-47f73872a75e',
  '00000000-0000-0000-0000-000000000001',
  $escape$NestJS Bull — Background Jobs Without the Boilerplate$escape$,
  $escape$NestJS integrates with Bull via `@nestjs/bull`, giving you Redis-backed task queues with decorators. Register a queue in any module with `BullModule.registerQueue({ name: 'email' })`, then inject it with `@InjectQueue('email')`. Producers call `queue.add('send-welcome', { userId })` — optionally passing delay, attempts, or backoff options. Consumers are plain classes decorated with `@Processor('email')`, with individual handlers marked `@Process('send-welcome')`. Each handler receives a `Job<T>` object exposing `job.data`, `job.progress()`, and `job.log()`. For scheduled work, `@nestjs/schedule` provides `@Cron()`, `@Interval()`, and `@Timeout()` decorators on any provider method — no separate worker process needed. In production, run Bull workers in a dedicated process by bootstrapping a separate NestJS app that only imports the processor modules, keeping HTTP latency isolated from heavy processing. Use `BullModule.registerQueueAsync()` for config-driven Redis connection strings loaded from `ConfigService`.$escape$,
  $escape$@Processor('email')
export class EmailProcessor {
  @Process('send-welcome')
  async handleWelcome(job: Job<{ userId: string }>) {
    await job.progress(10);
    await this.mailer.send(job.data.userId);
    await job.progress(100);
  }

  @OnQueueFailed()
  onFailed(job: Job, err: Error) {
    this.logger.error(`Job ${job.id} failed: ${err.message}`);
  }
}$escape$,
  $escape$typescript$escape$,
